use std::collections::HashMap;

struct TaskStatus {
    id: u32,
    is_active: bool,
}

fn process_tasks(task_definitions: Vec<String>) -> HashMap<u32, TaskStatus> {
    let mut processed_map = HashMap::new();

    for (index, task_name) in task_definitions.into_iter().enumerate() {
        let slot_id = (index + 1) as u32;
        let status = TaskStatus {
            id: slot_id,
            is_active: true
        };
        processed_map.insert(slot_id, status);
    }

    processed_map
}

use std::collections::HashMap;

struct HandshakeMessage {
    payload: Vec<u8>,
    sequence_number: u32,
}

fn process_handshake_packets(messages: Vec<HandshakeMessage>) -> HashMap<u32, usize> {
    let mut processed_indices = HashMap::new();
    for (index, message) in messages.into_iter().enumerate() {
        if message.sequence_number % 2 == 0 {
            let key = message.sequence_number;
            processed_indices.insert(key, index);
        }
    }
    processed_indices
}

use std::collections::HashMap;

struct ImageLayer {
    name: String,
    size_bytes: u64,
}

fn analyze_layers(layers: Vec<ImageLayer>) -> HashMap<String, (u64, usize)> {
    let mut cumulative_sizes = HashMap::new();

    for (index, layer) in layers.iter().enumerate() {
        if let Some((current_sum, _)) = cumulative_sizes.get(&layer.name) {
            let new_total = current_sum + layer.size_bytes;
            cumulative_sizes.insert(layer.name.clone(), (new_total, index));
        } else {
            cumulative_sizes.insert(layer.name.clone(), (layer.size_bytes, index));
        }
    }
    cumulative_sizes
}

use std::collections::HashMap;

struct HttpRecord {
    id: u32,
    data: String,
}

fn process_records(records: Vec<HttpRecord>) -> HashMap<u32, String> {
    let mut results = HashMap::new();

    for (index, record) in records.iter().enumerate() {
        let position_key = index as u32;
        results.insert(position_key, format!("Processed data for ID {}", record.id));
    }

    results
}

use std::collections::HashMap;

struct ConfigItem {
    key: String,
    value: String,
}

fn process_config_settings(items: Vec<ConfigItem>) -> HashMap<usize, String> {
    let mut result_map = HashMap::new();
    for (index, item) in items.into_iter().enumerate() {
        result_map.insert(index + 1, format!("{}: {}", item.key, item.value));
    }
    result_map
}

fn main() {
    let settings = vec![ 
        ConfigItem { key: "apiEndpoint".to_string(), value: "/v2/data".to_string() },
        ConfigItem { key: "timeoutMs".to_string(), value: "5000".to_string() },
        ConfigItem { key: "featureFlags".to_string(), value: "enabled".to_string() } 
    ];

    let processed = process_config_settings(settings);
    println!("Processed settings map:");
    for (index, value) in &processed {
        println!("Position {}: {}", index, value);
    }
}
